import { useState, useEffect } from "react";

import {
  AppBar,
  Toolbar,
  Typography,
  Box,
  Button,
  Container,
  Paper,
  TextField,
  MenuItem,
} from "@mui/material";

import { useNavigate } from "react-router-dom";

import "./CreatePage.css";

function CreatePage() {

  const navigate = useNavigate();

  // =========================
  // 로그인 확인
  // =========================
  useEffect(() => {

    const verifyUser = async () => {

      const token = localStorage.getItem("token");

      if (!token) {

        navigate("/");

        return;
      }

      try {

        const response = await fetch(
          "http://127.0.0.1:5000/profile",
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        if (!response.ok) {

          localStorage.removeItem("token");

          navigate("/");
        }

      } catch (error) {

        navigate("/");
      }
    };

    verifyUser();

  }, []);

  // =========================
  // state
  // =========================
  const [title, setTitle] = useState("");

  const [location, setLocation] = useState("");

  const [date, setDate] = useState("");

  const [category, setCategory] = useState("");

  const [storage, setStorage] = useState("");

  const [description, setDescription] = useState("");

  // =========================
  // 게시물 등록
  // =========================
  const handleSubmit = async () => {

    const token = localStorage.getItem("token");

    try {

      await fetch(
        "http://127.0.0.1:5000/posts",
        {
          method: "POST",

          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },

          body: JSON.stringify({

            title,

            location,

            date,

            category,

            storage,

            description,

            image:
              "https://via.placeholder.com/300",
          }),
        }
      );

      navigate("/board");

    } catch (error) {

      console.log(error);
    }
  };

  return (
    <>
      {/* Navbar */}
      <AppBar
        position="static"
        className="create-navbar"
      >
        <Toolbar className="create-navbar-toolbar">

          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

        </Toolbar>
      </AppBar>

      {/* 배너 */}
      <Box className="create-header">

        <Typography
          variant="h4"
          className="create-title"
        >
          유실물 등록
        </Typography>

        <Typography className="create-subtitle">
          유실물 정보를 입력해주세요
        </Typography>

      </Box>

      {/* 폼 */}
      <Container maxWidth="md">

        <Paper className="create-paper">

          {/* 제목 */}
          <TextField
            fullWidth
            label="제목"
            margin="normal"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />

          {/* 습득 장소 */}
          <TextField
            fullWidth
            label="습득 장소"
            margin="normal"
            value={location}
            onChange={(e) => setLocation(e.target.value)}
          />

          {/* 습득 일자 */}
          <TextField
            fullWidth
            type="date"
            label="습득 일자"
            InputLabelProps={{
              shrink: true,
            }}
            margin="normal"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />

          {/* 물품 분류 */}
          <TextField
            fullWidth
            select
            label="물품 분류"
            margin="normal"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
          >
            <MenuItem value="노트북">
              노트북
            </MenuItem>

            <MenuItem value="태블릿">
              태블릿
            </MenuItem>

            <MenuItem value="휴대폰">
              휴대폰
            </MenuItem>

            <MenuItem value="학생증">
              학생증
            </MenuItem>

            <MenuItem value="에어팟">
              에어팟
            </MenuItem>

            <MenuItem value="지갑">
              지갑
            </MenuItem>

            <MenuItem value="가방">
              가방
            </MenuItem>
          </TextField>

          {/* 보관 장소 */}
          <TextField
            fullWidth
            select
            label="보관 장소"
            margin="normal"
            value={storage}
            onChange={(e) => setStorage(e.target.value)}
          >
            <MenuItem value="화도관 경비실">
              화도관 경비실
            </MenuItem>

            <MenuItem value="비마관 경비실">
              비마관 경비실
            </MenuItem>

            <MenuItem value="새빛관 경비실">
              새빛관 경비실
            </MenuItem>

            <MenuItem value="참빛관 경비실">
              참빛관 경비실
            </MenuItem>
          </TextField>

          {/* 상세 정보 */}
          <TextField
            fullWidth
            multiline
            rows={5}
            label="상세 정보"
            margin="normal"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
          />

          {/* 등록 버튼 */}
          <Button
            fullWidth
            variant="contained"
            className="submit-button"
            onClick={handleSubmit}
          >
            게시물 등록
          </Button>

        </Paper>

      </Container>
    </>
  );
}

export default CreatePage;
